（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01259', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'essay', '政府的通報、登記及行政資料常用於監測及評估社區中疾病及傷害的
