  ('public-health-specialist-moex-01260', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '描述性流行病學有許多指標，下列何者有牽涉到人時的概念？', '["累積發生率（cumulativeincidence）", "發生率（incidencedensityrate）", "盛行率（prevalence）", "侵襲率（attackrate）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01261', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列有關年齡標準化死亡比率（ageadjustedmortalityrate）的敘述，何者錯誤？', '["比較不同國家別的死亡情形", "去除年齡結構不同的干擾影響", "計算不同群體其標準化死亡比（StandardizedMortalityRatio,SMR）時，即使使用相同的參 考族群數據，不同群體間的標準化死亡比多半無法互相比較", "經過標準化後所算出來的死亡率即為真正的死亡率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01262', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究者進行世代研究，分析SARS-CoV-2確診個案體內維生素D狀況與後續是否發生重症 的機率，得到以下資料（數字皆為人數），請問下列敘述何者正確？ 維生素D缺乏 維生素D正常 重症 30 30 無重症 120 270', '["維生素D缺乏與重症發生的勝算比（oddsratio）為2.0", "維生素D缺乏與重症發生的風險比（riskratio）為2.0", "維生素D缺乏與重症發生的發生率比（incidencerateratio）為2.0", "當勝算比大於1時，同一組數據所計算得到的勝算比會比風險比來得低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01263', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於生命表與平均餘命的估計，下列何者正確？', '["利用生命表推估平均餘命，是採用世代研究的方式，長期追蹤一般民眾以了解實際存活情形", "利用生命表推估平均餘命，需要假設年齡別死亡率不隨時間改變", "依據109年的生命表，國人零歲平均餘命為81.3年，這表示該年之10歲平均餘命為71.3年", "活得長未必活得健康，平均餘命同時反映了平均壽命的長短以及健康水準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01264', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '想要計算2021年臺灣攝護腺癌全年發生率（incidence），分子是2021年臺灣新發生之攝護腺 癌個案數，則其分母為下列何者？', '["2021年臺灣全人口數", "2021年臺灣全部男性人口數", "2021年臺灣男性有機會得到攝護腺癌，但尚未罹患的人口數", "2021年臺灣全部男性罹患癌症的個案數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01265', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列那一個指標最適合用於描述農藥使用與巴金森氏病的相關性，而此資料取自於一項社區 型問卷調查的數據，此研究為招募有興趣的社區民眾參與並以自填式的方式完成問卷內容？', '["盛行率比（prevalenceratio）", "危險差異（riskdifference）", "危險比（riskratio）", "風險比（hazardratio）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01266', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關發生率（incidencerate）、盛行率以及死亡率之敘述，下列何者正確？', '["發生率可透過橫斷性研究來測量", "醫療技術的進步可以降低死亡率，在疾病發生率不改變的情形下，反而會使得疾病盛行率 上升", "在疾病的病程長短固定的前提下，發生率跟盛行率之間會呈負相關", "發生率的計算，是由發病人數除以總人數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
